    asl A
    adc $04
    clc
    adc $06
    sta $06
    sta $0A
    lda $08
    sta $0C
    inc $0A
    inc $0A
    ldy $02
    lda [$0A]
    and.w #CastNamePointerRecordBankByteMask
    tax
    lda [$06]
    jsl CopyCastNameTilemap
    lda [$0A]
    and.w #CastNamePointerRecordBankByteMask
    tay
    lda $10
    sta $04
    ldx $04
    lda $02
    jsl PrintCastName
    pld
    rtl
